const e=`{% block sw_cms_block_app_preview_renderer %} <div class="sw-cms-block-app-preview-renderer"> <img v-if="previewImage" :src="previewImage" :alt="'Preview image for app CMS block: ' + $t(blockLabel)" > <sw-extension-teaser-popover v-else-if="appName === 'SwagRecommendations'" position-identifier="sw-cms-block-3d-object" /> <section v-else class="sw-cms-block-app-preview-renderer__fallback-preview" > <h2> {{ $t(appName) }} </h2> </section> </div> {% endblock %}`,p=Shopware.Component.wrapComponentConfig({template:e,props:{block:{type:Object,required:!1,default(){return{}}}},computed:{previewImage(){return this.block.previewImage},blockLabel(){return this.block.label??""},appName(){return this.block.appName??""}}});export{p as default};
